from vex import RiskLevel

@vex_client.listener("soc2-compliance")
def enforce_human_approval(event):
    critical_tools = ['block_ip', 'quarantine_host', 'edr_kill_process']

    if (event.type == EventType.TOOL_CALL and 
        event.payload.tool.name in critical_tools):

        approval = vex_client.request_approval(
            event_id=event.id,
            risk=RiskLevel.CRITICAL,
            context={
                'tool': event.payload.tool.name,
                'target': event.payload.input.get('target'),
                'reason': event.payload.input.get('reason')
            },
            approvers=['soc-analyst-team']
        )

        if not approval.granted:
            vex_client.block(event, reason="Human approval required")

import requests
from vex import Guardrail

@vex.guardrail("cve-validation")
def validate_cve_advisory(event):
    if event.type == EventType.LLM_OUTPUT:
        content = event.payload.content

        # Extract CVE patterns
        cve_ids = vex.extract_cve_ids(content)

        for cve_id in cve_ids:
            if not is_valid_cve(cve_id):
                vex_client.block(event, reason=f"Invalid CVE: {cve_id}")
                return False
    return True

@vex_client.listener("advisory-validation")
def apply_cve_guardrail(event):
    validate_cve_advisory(event)

# External CVE validation
def is_valid_cve(cve_id):
    try:
        response = requests.get(f'https://services.nvd.nist.gov/rest/json/cves/2.0?cveId={cve_id}')
        return response.status_code == 200
    except:
        return False
